import React, { useState, useEffect } from 'react';
import RefreshIcon from '@mui/icons-material/Refresh';
import axios from 'axios';

const Zoom = () => {
  const [authenticated, setAuthenticated] = useState(false);
  const [contacts, setContacts] = useState([]);
  const [error, setError] = useState('');
  const [backendUrl, setBackendUrl] = useState('http://localhost:8000');  // Backend URL

  // Verifică dacă utilizatorul este autentificat
  const checkAuthentication = () => {
    axios.get(`${backendUrl}/shortcuts/zoom/check-auth/`)
      .then(response => {
        if (response.data.authenticated) {
          setAuthenticated(true);
          fetchContacts(); // După autentificare, preia lista de contacte
        } else {
          // Redirecționează utilizatorul pentru autentificare dacă nu este autentificat
          window.location.href = `${backendUrl}/shortcuts/zoom/oauth/login/`;
        }
      })
      .catch(err => {
        console.error('Eroare la verificarea autentificării:', err);
      });
  };

  // Funcția pentru a prelua lista de contacte Zoom
  const fetchContacts = () => {
    axios.get(`${backendUrl}/shortcuts/zoom/get-contacts/`)
      .then(response => {
        if (response.data.success) {
          setContacts(response.data.contacts);
        } else {
          setError('Nu s-au putut obține contactele');
        }
      })
      .catch(err => {
        console.error('Eroare la preluarea contactelor:', err);
        setError('A apărut o eroare la preluarea contactelor');
      });
  };

  useEffect(() => {
    checkAuthentication(); // Verifică autentificarea la încărcarea componentei
  }, []);

  const handleActivateZoom = () => {
    axios.post(`${backendUrl}/shortcuts/zoom/open-zoom/`)
      .then(response => {
        if (response.data.success) {
          console.log('Zoom a fost deschis cu succes!');
        }
      })
      .catch(error => {
        console.error('Eroare la activarea Zoom:', error);
      });
  };

  return (
    <div className="zoom-container">
      {!authenticated ? (
        <button onClick={checkAuthentication} className="button login-button">
          Autentificare cu Zoom
        </button>
      ) : (
        <>
          <h1>Contactele Zoom</h1>
          {error && <p className="error">{error}</p>}
          {contacts.length > 0 ? (
            <ul className="contacts-list">
              {contacts.map((contact, index) => (
                <li key={index}>
                  <strong>{contact.first_name} {contact.last_name}</strong> - {contact.email}
                </li>
              ))}
            </ul>
          ) : (
            <p>Nu există contacte de afișat.</p>
          )}

          <div className="button-container">
            <button onClick={handleActivateZoom} className="button activate-zoom-button">
              <RefreshIcon className="button-icon" /> Adu în față Zoom
            </button>
          </div>
        </>
      )}
    </div>
  );
};

export default Zoom;
